import React from 'react';
import { Link } from 'react-router-dom';

export default function Home() {
  return (
    <div>
      {/* Hero Section */}
      <section style={hero}>
        <div style={heroContent}>
          <h1 style={heroTitle}>Your Health, Our Priority</h1>
          <p style={heroSubtitle}>
            Book hospital appointments online with ease. Find the right doctor,
            choose a convenient time, and skip the long queues.
          </p>
          <div style={{display:'flex', gap:'1rem', flexWrap:'wrap'}}>
            <Link to="/register" style={ctaPrimary}>Get Started – It's Free</Link>
            <Link to="/login" style={ctaSecondary}>Already have an account?</Link>
          </div>
        </div>
      </section>

      {/* Features */}
      <section style={featuresSection}>
        <h2 style={sectionHeading}>Why Choose Arogya?</h2>
        <div style={featuresGrid}>
          {features.map((f, i) => (
            <div key={i} style={featureCard}>
              <div style={featureIcon}>{f.icon}</div>
              <h3 style={featureTitle}>{f.title}</h3>
              <p style={featureDesc}>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* How It Works */}
      <section style={howSection}>
        <h2 style={sectionHeading}>How It Works</h2>
        <div style={stepsGrid}>
          {steps.map((s, i) => (
            <div key={i} style={stepCard}>
              <div style={stepNumber}>{i + 1}</div>
              <h3 style={featureTitle}>{s.title}</h3>
              <p style={featureDesc}>{s.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Departments */}
      <section style={deptSection}>
        <h2 style={sectionHeading}>Our Departments</h2>
        <div style={deptGrid}>
          {departments.map((d, i) => (
            <div key={i} style={deptCard}>
              <span style={{fontSize:'2rem'}}>{d.icon}</span>
              <span style={{fontWeight:600}}>{d.name}</span>
            </div>
          ))}
        </div>
      </section>

      {/* CTA */}
      <section style={ctaSection}>
        <h2 style={{fontSize:'2rem', fontWeight:800, marginBottom:'0.75rem', color:'#fff'}}>
          Ready to book your appointment?
        </h2>
        <p style={{color:'rgba(255,255,255,.85)', marginBottom:'1.5rem', fontSize:'1.1rem'}}>
          Join thousands of patients who trust Arogya for their healthcare needs.
        </p>
        <Link to="/register" style={{...ctaPrimary, background:'#fff', color:'#6610f2', fontSize:'1.1rem', padding:'0.9rem 2.5rem'}}>
          Create Free Account
        </Link>
      </section>

      {/* Footer */}
      <footer style={footer}>
        <p>© 2026 Arogya Hospital Appointment Management System. Built by Pijush Pakrashi, Heritage Institute of Technology.</p>
      </footer>
    </div>
  );
}

/* ── Data ─────────────────────────────────────────────────── */
const features = [
  { icon: '🔍', title: 'Find Doctors', desc: 'Search doctors by name, specialization, or department and view their profiles.' },
  { icon: '📅', title: 'Easy Booking', desc: 'Select your preferred date and time slot with just a few clicks.' },
  { icon: '🔔', title: 'Instant Notifications', desc: 'Get confirmation notifications for every booking, cancellation, or reschedule.' },
  { icon: '🔒', title: 'Secure & Private', desc: 'Your data is encrypted and protected with industry-standard security.' },
  { icon: '📱', title: 'Works Everywhere', desc: 'Access Arogya from any device — desktop, tablet, or smartphone.' },
  { icon: '⚡', title: 'Fast & Reliable', desc: 'Lightning-fast page loads and 99.5% uptime guaranteed.' },
];

const steps = [
  { title: 'Register', desc: 'Create a free account with your email.' },
  { title: 'Browse Doctors', desc: 'Search by department or specialization.' },
  { title: 'Pick a Slot', desc: 'Choose a date and available time slot.' },
  { title: 'Confirm', desc: 'Book your appointment instantly!' },
];

const departments = [
  { icon: '❤️', name: 'Cardiology' },
  { icon: '🧠', name: 'Neurology' },
  { icon: '🦴', name: 'Orthopedics' },
  { icon: '👶', name: 'Pediatrics' },
  { icon: '🦷', name: 'Dentistry' },
  { icon: '👁️', name: 'Ophthalmology' },
  { icon: '🩺', name: 'General Medicine' },
  { icon: '👂', name: 'ENT' },
];

/* ── Styles ───────────────────────────────────────────────── */
const hero = { background:'linear-gradient(135deg,#667eea 0%,#764ba2 100%)', padding:'5rem 2rem', textAlign:'center', display:'flex', justifyContent:'center' };
const heroContent = { maxWidth:'700px' };
const heroTitle = { fontSize:'3rem', fontWeight:800, color:'#fff', marginBottom:'1rem', lineHeight:1.15 };
const heroSubtitle = { fontSize:'1.15rem', color:'rgba(255,255,255,.9)', marginBottom:'2rem', lineHeight:1.6 };
const ctaPrimary = { display:'inline-block', padding:'0.85rem 2rem', background:'#fff', color:'#764ba2', borderRadius:'10px', fontWeight:700, fontSize:'1rem', textDecoration:'none', boxShadow:'0 4px 15px rgba(0,0,0,.2)', transition:'transform .25s' };
const ctaSecondary = { display:'inline-flex', alignItems:'center', padding:'0.85rem 2rem', background:'transparent', color:'#fff', borderRadius:'10px', fontWeight:600, fontSize:'1rem', textDecoration:'none', border:'2px solid rgba(255,255,255,.4)' };

const featuresSection = { padding:'4rem 2rem', maxWidth:'1100px', margin:'0 auto' };
const sectionHeading = { textAlign:'center', fontSize:'1.75rem', fontWeight:800, marginBottom:'2.5rem', color:'#212529' };
const featuresGrid = { display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(300px, 1fr))', gap:'1.5rem' };
const featureCard = { background:'#fff', borderRadius:'14px', padding:'2rem', boxShadow:'0 2px 12px rgba(0,0,0,.06)', transition:'transform .25s', textAlign:'center' };
const featureIcon = { fontSize:'2.5rem', marginBottom:'0.75rem' };
const featureTitle = { fontSize:'1.1rem', fontWeight:700, marginBottom:'0.5rem', color:'#212529' };
const featureDesc = { color:'#6c757d', lineHeight:1.6, fontSize:'0.9rem' };

const howSection = { padding:'4rem 2rem', background:'#f8f9fa', textAlign:'center' };
const stepsGrid = { display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(200px, 1fr))', gap:'2rem', maxWidth:'900px', margin:'0 auto' };
const stepCard = { background:'#fff', borderRadius:'14px', padding:'2rem', boxShadow:'0 2px 12px rgba(0,0,0,.06)' };
const stepNumber = { width:'48px', height:'48px', borderRadius:'50%', background:'linear-gradient(135deg,#667eea,#764ba2)', color:'#fff', display:'inline-flex', alignItems:'center', justifyContent:'center', fontWeight:800, fontSize:'1.25rem', marginBottom:'1rem' };

const deptSection = { padding:'4rem 2rem', maxWidth:'900px', margin:'0 auto' };
const deptGrid = { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(180px, 1fr))', gap:'1rem' };
const deptCard = { background:'#fff', borderRadius:'12px', padding:'1.25rem', boxShadow:'0 2px 8px rgba(0,0,0,.06)', display:'flex', alignItems:'center', gap:'0.75rem', transition:'transform .25s' };

const ctaSection = { background:'linear-gradient(135deg,#667eea 0%,#764ba2 100%)', padding:'4rem 2rem', textAlign:'center' };

const footer = { background:'#212529', color:'rgba(255,255,255,.6)', textAlign:'center', padding:'1.5rem', fontSize:'0.85rem' };
